1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	export type Damage = { itemType: string; amount: number };
3	export type Incident = { cause: string; damages: Damage[] };
4	export type QuoteStep = { op: "quote"; items: Item[] };
5	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	export type Step = QuoteStep | ClaimStep;
7	export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
8	export type QuoteResult = { premium: number };
9	export type ClaimResult = { payout: number; remainingCap: number };
10	export type ScenarioResult = { results: Array<QuoteResult | ClaimResult> };
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_RATE = 0.1;
14	const CURSE_SURCHARGE_RATE = 0.5;
15	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const LOYALTY_DISCOUNT_RATE = 0.2;
18	const LOYALTY_THRESHOLD_YEARS = 2;
19	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
20	const DEDUCTIBLE = 100;
21	const CAP_MULTIPLIER = 2;
22	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
23	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
24	
25	type Customer = { yearsWithMHPCO: number };
26	const COMPONENT_UNIT_BASE = 25;
27	const COMPONENT_BLOCK_SIZE = 3;
28	const COMPONENT_BLOCK_BASE = 60;
29	
30	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	};
36	
37	const ITEM_INSURANCE_VALUE: Record<string, number> = {
38	  sword: 1000,
39	  amulet: 600,
40	  staff: 800,
41	  potion: 400,
42	  rune: 250,
43	  moonstone: 250,
44	};
45	
46	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
47	
48	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
49	
50	type BillingGroup = { base: number; cursed: boolean; enchantment: number };
51	
52	const componentBundleBase = (count: number): number => {
53	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_BASE;
54	  return count * COMPONENT_UNIT_BASE;
55	};
56	
57	const billingGroups = (items: Item[]): BillingGroup[] => {
58	  const groups: BillingGroup[] = [];
59	  const componentCounts = new Map<string, number>();
60	  for (const item of items) {
61	    if (isComponent(item)) {
62	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
63	    } else if (item.type in MAIN_ITEM_BASE_PREMIUM) {
64	      groups.push({
65	        base: MAIN_ITEM_BASE_PREMIUM[item.type],
66	        cursed: item.cursed === true,
67	        enchantment: item.enchantment ?? 0,
68	      });
69	    } else {
70	      throw new Error(`Unknown item type: ${item.type}`);
71	    }
72	  }
73	  for (const count of componentCounts.values()) {
74	    groups.push({ base: componentBundleBase(count), cursed: false, enchantment: 0 });
75	  }
76	  return groups;
77	};
78	
79	const groupPremium = ({ base, cursed, enchantment }: BillingGroup): number => {
80	  const curseSurcharge = cursed ? base * CURSE_SURCHARGE_RATE : 0;
81	  const enchantmentSurcharge =
82	    enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
83	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
84	  return base + curseSurcharge + enchantmentSurcharge + firstInsuranceSurcharge;
85	};
86	
87	const sumGroupPremiums = (groups: BillingGroup[]): number =>
88	  groups.reduce((sum, g) => sum + groupPremium(g), 0);
89	
90	const policyBaseOf = (groups: BillingGroup[]): number =>
91	  groups.reduce((sum, g) => sum + g.base, 0);
92	
93	const loyaltyDiscountOf = (policyBase: number, customer: Customer): number =>
94	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
95	
96	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
97	  const groups = billingGroups(items);
98	  const itemsTotal = sumGroupPremiums(groups);
99	  const policyBase = policyBaseOf(groups);
100	  const loyaltyDiscount = loyaltyDiscountOf(policyBase, customer);
101	  const followUpDiscount = isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
102	  return Math.ceil(itemsTotal - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
103	};
104	
105	type Policy = { items: Item[]; cap: number };
106	
107	const insuranceSumOf = (items: Item[]): number =>
108	  items.reduce((sum, item) => sum + ITEM_INSURANCE_VALUE[item.type], 0);
109	
110	const isHighlyEnchantedForPayout = (item: Item | undefined): boolean =>
111	  item !== undefined && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
112	
113	const reimbursableAmount = (amount: number, item: Item | undefined): number =>
114	  isHighlyEnchantedForPayout(item) ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE : amount;
115	
116	const damagePayout = (damage: Damage, item: Item | undefined): number =>
117	  Math.max(0, reimbursableAmount(damage.amount, item) - DEDUCTIBLE);
118	
119	const findInsuredItem = (policy: Policy, itemType: string): Item | undefined =>
120	  policy.items.find((i) => i.type === itemType);
121	
122	const incidentPayout = (policy: Policy, incident: Incident): number =>
123	  incident.damages.reduce(
124	    (sum, d) => sum + damagePayout(d, findInsuredItem(policy, d.itemType)),
125	    0,
126	  );
127	
128	const newPolicy = (items: Item[]): Policy => ({
129	  items,
130	  cap: insuranceSumOf(items) * CAP_MULTIPLIER,
131	});
132	
133	const cappedPayout = (policy: Policy, incident: Incident): number =>
134	  Math.floor(Math.min(incidentPayout(policy, incident), policy.cap));
135	
136	const settleClaim = (policy: Policy, incident: Incident): ClaimResult => {
137	  const payout = cappedPayout(policy, incident);
138	  policy.cap -= payout;
139	  return { payout, remainingCap: policy.cap };
140	};
141	
142	export const runScenario = (scenario: Scenario): ScenarioResult => {
143	  const policies: Policy[] = [];
144	  const results = scenario.steps.map((step) => {
145	    if (step.op === "quote") {
146	      const isFollowUp = policies.length > 0;
147	      policies.push(newPolicy(step.items));
148	      return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
149	    }
150	    return settleClaim(policies[step.policy], step.incident);
151	  });
152	  return { results };
153	};
